module register(D, CLK, LOAD, RST, Q);
input [3:0] D;
input CLK, LOAD, RST;
output reg [3:0] Q;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always@(posedge CLK or posedge RST or posedge dbg_halt) begin
    if(RST)
        Q <= 4'b0000;
    else if(LOAD)
        Q <= D;
end

endmodule
